transform.script:
const { complexity, taskType, reasoning } = result;
const taskText = triggeringMessage.content?.text || '';

if (complexity === 'UNCERTAIN') {
  return {
    topic: 'CONDUCTOR_ESCALATE',
    content: {
      text: reasoning,
      data: { complexity, taskType, reasoning, taskText }
    }
  };
}

const config = helpers.getConfig(complexity, taskType);

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `[${complexity}:${taskType}] ${reasoning}`,
    data: {
      complexity,
      taskType,
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};

const { complexity, taskType, reasoning } = result;

let taskText = triggeringMessage.content?.data?.taskText || '';
if (!taskText) {
  taskText = triggeringMessage.content?.text || '';
}

const config = helpers.getConfig(complexity, taskType);

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `Senior: [${complexity}:${taskType}] ${reasoning}`,
    data: {
      complexity,
      taskType,
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};
